#!/usr/bin/env python3
import json, os

OUT = "/Users/kallolchakraborty/Proof Of Concepts/Quick Reference - GitHub Pages/content/product/product-sense-staff.json"

def bd(label, color="#E95420"):
    bg = f"rgba({','.join(str(int(color[i:i+2],16)) for i in (1,3,5))},0.08)"
    return f'<div style="margin-bottom:16px"><span style="display:inline-block;background:{bg};border:1px solid {color};color:{color};font:700 10px system-ui;padding:3px 10px;border-radius:99px;letter-spacing:.05em">{label}</span></div>'

def mg(items):
    r = "".join(f'<div style="background:#f8fafc;border:1.5px solid #e2e8f0;border-radius:8px;padding:14px">{item}</div>' for item in items)
    return f'<div style="margin:16px 0;display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:10px">{r}</div>'

def tb(hd, rows):
    th = "".join(f'<th style="padding:10px 12px;border-bottom:2px solid #e2e8f0;color:#475569;font-weight:700;text-align:left;font-size:11px">{h}</th>' for h in hd)
    tr = ""
    for i, r in enumerate(rows):
        bg = 'background:#fafafa' if i%2 else ''
        tr += f'<tr style="border-bottom:1px solid #f1f5f9;{bg}>' + "".join(f'<td style="padding:9px 12px;font-size:12px{f";font-weight:600" if j==0 else ""}">{c}</td>' for j,c in enumerate(r)) + '</tr>'
    return f'<div style="margin:16px 0;overflow-x:auto"><table style="width:100%;border-collapse:collapse;font:12px system-ui,sans-serif"><thead><tr style="background:#f1f5f9;text-align:left">{th}</tr></thead><tbody>{tr}</tbody></table></div>'

S = []

S.append({
    "id": "product-sense-staff-1",
    "title": "Product Sense for Staff+: Why It Matters",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Product sense at the Staff+ level is not about shipping features faster — it is about identifying which problems are worth solving, defining the right outcomes, and aligning technical investments with business strategy. While junior engineers execute against defined requirements, Staff+ engineers are expected to shape the product direction itself.") + bd("<b>Why Product Sense Separates Staff+ Engineers</b>") + mg(["<b>Strategic Alignment:</b> Staff+ engineers connect technical decisions to business outcomes, ensuring every investment moves a metric that matters", "<b>Ambiguity Resolution:</b> When product requirements are fuzzy, Staff+ engineers clarify the problem space before writing a line of code", "<b>Opportunity Identification:</b> The best features often come from engineers who deeply understand user needs — Staff+ engineers spot these opportunities proactively", "<b>Trade-Off Articulation:</b> Product sense enables you to articulate why a technically elegant solution might not be the right product decision, and vice versa", "<b>Cross-Functional Credibility:</b> Engineers with strong product sense earn trust from PMs, designers, and executives, becoming strategic partners rather than order-takers"]) + bd("At FAANG, product sense is evaluated through dedicated interview rounds where you design features, analyze metrics, and prioritize roadmaps. This guide covers the frameworks and mental models you need to excel."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "staff-plus", "interview-prep", "product-thinking", "faang"]
})

S.append({
    "id": "product-sense-staff-2",
    "title": "User-Centric Thinking: Personas, Needs & Jobs to Be Done",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("At the core of product sense is a deep understanding of users. Staff+ engineers must think beyond surface-level feature requests and uncover the underlying jobs users are trying to accomplish. The Jobs to Be Done (JTBD) framework is the gold standard for this.") + bd("<b>Jobs to Be Done Framework</b>") + mg(["<b>Functional Job:</b> The practical task the user wants to accomplish. \"I need to share a file with my team so they can edit it simultaneously.\"", "<b>Emotional Job:</b> How the user wants to feel. \"I want to feel competent and collaborative, not like I'm creating confusion with email attachments.\"", "<b>Social Job:</b> How the user wants to be perceived. \"I want to be seen as an organized, team-oriented person who uses modern tools.\"", "<b>Core Functional Need:</b> The fundamental outcome the user measures success by. \"The file should be accessible, editable, and versioned without manual effort.\""]) + bd("<b>Persona Segmentation for Product Interviews</b>") + tb(["Persona Dimension", "Questions to Ask", "Impact on Design"], [["Demographics", "Age range? Technical literacy? Industry?", "Informs UX complexity, onboarding flow, support needs"], ["Usage Context", "Desktop vs mobile? Office vs field? Alone vs team?", "Drives platform choice, offline needs, collaboration features"], ["Frequency of Use", "Daily power user? Weekly casual? Once ever?", "Determines shortcut depth, onboarding investment, notification strategy"], ["User Goals", "What does success look like for them?", "Defines the primary metric and success criteria"], ["Pain Points", "What frustrates them about current solutions?", "Identifies the switching cost and adoption barrier"]]) + bd("In a product design interview, start by explicitly stating the target user persona and their primary job to be done before proposing any solution."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "user-centric", "jtbd", "personas", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-3",
    "title": "Problem Definition: The Most Underrated Skill",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Most product sense interview failures happen not because the proposed feature is wrong, but because the candidate solved the wrong problem. Problem definition is the highest-leverage skill in the product sense toolkit.") + bd("<b>The Problem Definition Protocol</b>") + mg(["<b>1. Clarify the goal:</b> \"What metric or outcome are we trying to improve? How is it measured today?\"", "<b>2. Identify the user:</b> \"Who specifically experiences this problem? Is it one persona or multiple?\"", "<b>3. Understand current behavior:</b> \"How do users solve this today? What workarounds exist?\"", "<b>4. Quantify the pain:</b> \"How much time/money/effort does the current approach cost? What is the gap?\"", "<b>5. Define success criteria:</b> \"What specifically would count as a win? What threshold matters?\"", "<b>6. Validate assumptions:</b> \"What evidence do we have that this is the right problem? What could disprove it?\""]) + bd("<b>Clarification Questions Every Staff+ Engineer Should Ask</b>") + tb(["Question", "Why It Matters", "What It Reveals"], [["What metric is this expected to move?", "Forces alignment on success measurement", "Whether the goal is growth, retention, engagement, or revenue"], ["Who is the target user?", "Prevents designing for the wrong audience", "Whether this serves power users, new users, or a specific segment"], ["What is the current baseline?", "Establishes whether the problem is real", "Gives you a before/after comparison point"], ["What constraints exist?", "Identifies real boundaries vs imagined ones", "Technical, regulatory, resourcing, or timeline constraints"], ["Why now?", "Reveals urgency and context", "Competitive pressure, user feedback, strategic shift, or regulatory change"], ["What have we tried before?", "Prevents repeating failed approaches", "Previous learnings, hypotheses tested, and why they failed"]]) + bd("Take 3-4 minutes at the start of any product question to define and narrow the problem. Interviewers explicitly look for this discipline."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "problem-definition", "framing", "interview-prep", "staff-plus"]
})

S.append({
    "id": "product-sense-staff-4",
    "title": "Metrics-Driven Product Thinking",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Staff+ engineers must think in metrics. Every product decision should be anchored to measurable outcomes. The best product sense answers explicitly state which metrics matter and why.") + bd("<b>North Star Metrics vs Vanity Metrics</b>") + mg(["<b>North Star Metric:</b> The single metric that best captures the long-term value your product delivers. For Airbnb, it is nights booked. For Spotify, it is time spent listening. For Slack, it is messages sent.", "<b>Counter Metric:</b> What could improve while the product actually gets worse? Every North Star needs a guardrail metric to prevent gaming the system.", "<b>Leading Indicator:</b> A metric that predicts future success. For a social app, it might be daily active users (leading) vs annual revenue (lagging).", "<b>Lagging Indicator:</b> A metric that confirms past success. Revenue, retention at 12 months, and customer lifetime value are lagging.", "<b>Input Metric:</b> Something your team can directly control. Number of onboarding steps completed directly impacts activation rate (output)."]) + bd("<b>Leading vs Lagging Metrics Framework</b>") + tb(["Metric Type", "Definition", "Example", "Use Case"], [["Leading", "Predicts future outcomes", "Weekly active users", "Short-term tactical decisions, experimentation"], ["Lagging", "Confirms past outcomes", "Quarterly revenue", "Strategic reviews, investor reporting"], ["Input", "Directly controllable", "Number of invites sent", "Daily team execution, sprint goals"], ["Output", "Result of inputs", "Activation rate", "Weekly/monthly health check"], ["North Star", "Ultimate success metric", "Nights booked", "Company-wide alignment, long-term strategy"]]) + bd("<b>AARA Framework: Align, Analyze, Recommend, Assess</b>") + mg(["<b>Align:</b> Confirm which metric matters with the interviewer. \"Before diving in, I want to confirm we are optimizing for x.\"", "<b>Analyze:</b> Break down the metric into its component parts. Use a metrics tree or formula decomposition.", "<b>Recommend:</b> Propose a feature or change and predict its impact on the decomposed metrics.", "<b>Assess:</b> Describe how you would measure success — what experiment would you run? What is the minimum detectable effect?"]) + bd("The AARA framework ensures your product thinking is grounded in measurable impact rather than subjective opinion."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "metrics", "north-star", "aara", "leading-indicators", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-5",
    "title": "Prioritization Frameworks: RICE, ICE & Opportunity Scoring",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Staff+ engineers constantly face more ideas than resources. How you prioritize reveals your product judgment. Strong candidates reference formal prioritization frameworks and customize them to the context.") + bd("<b>RICE Framework (Intercom)</b>") + mg(["<b>Reach:</b> How many users will this impact in a given time period? Measured in number of users or events per quarter.", "<b>Impact:</b> How much will this move the target metric? Usually scored 1-3 (minimal-massive) or as a percentage.", "<b>Confidence:</b> How certain are you of your estimates? 100% = strong data, 80% = solid proxy, 50% = informed guess, 20% = pure intuition.", "<b>Effort:</b> How many person-weeks or engineering-months will this require? Includes cross-team dependencies.", "<b>RICE Score:</b> (Reach x Impact x Confidence) / Effort. Higher is better. Compare across projects in the same context."]) + bd("<b>Prioritization Framework Comparison</b>") + tb(["Framework", "Best For", "Inputs", "Output"], [["RICE", "Feature prioritization with data", "Reach, Impact, Confidence, Effort", "Single score for ranking"], ["ICE", "Rapid scoring, less data available", "Impact, Confidence, Ease", "Quick comparison score"], ["Opportunity Scoring", "Identifying underserved needs", "Importance, Satisfaction (survey data)", "Opportunity = Importance - Satisfaction"], ["Kano Model", "Feature categorization", "User delight vs investment cost", "Must-have, Performance, Delighter categories"], ["MoSCoW", "Scope management for releases", "Stakeholder priorities, dependencies", "Must, Should, Could, Won't"], ["Cost of Delay", "Urgency-driven prioritization", "Time value, criticality, risk reduction", "Dollar value per unit time"]]) + bd("<b>Applying Prioritization in Interviews</b>") + mg(["<b>1. Establish criteria:</b> \"I will prioritize features based on user impact, engineering effort, and strategic alignment.\"", "<b>2. Score each option:</b> Walk through 2-3 features and assign scores. Be transparent about confidence levels.", "<b>3. Recommend an order:</b> \"Given these scores, I recommend the sequence: Feature A first, then C, then B.\"", "<b>4. Justify trade-offs:</b> \"I chose A over B even though B has higher impact because A has higher confidence and takes half the effort.\"", "<b>5. Consider dependencies:</b> \"Feature B depends on infrastructure work in Feature A, so we should do A first regardless.\""]) + bd("The framework matters less than your reasoning. Interviewers want to see structured thinking, not a memorized formula."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "prioritization", "rice", "ice", "opportunity-scoring", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-6",
    "title": "Designing for Edge Cases: The Staff+ Differentiator",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Junior product thinkers design for the happy path. Staff+ product thinkers design for the unhappy path — edge cases, failure modes, and extreme users. This is one of the clearest signals of seniority in product sense interviews.") + bd("<b>Types of Edge Cases to Consider</b>") + mg(["<b>User Edge Cases:</b> Power users doing things at extreme scale. Novice users who need hand-holding. Users with disabilities. Users on slow networks or older devices.", "<b>Data Edge Cases:</b> Empty states. Error states. Malicious input. Duplicate data. Extremely long text. Special characters. Non-Latin scripts.", "<b>System Edge Cases:</b> Network failures. Timeouts. Race conditions. Data loss. Concurrent edits. Rate limiting. Backend unavailability.", "<b>Business Edge Cases:</b> Free tier hitting limits. International users with different regulations. Payment failures. Refund flows. Account deletion and data portability.", "<b>UX Edge Cases:</b> Users navigating in unexpected order. Browser back button. Multiple tabs. Popup blockers. Ad blockers. Notifications permission denied."]) + bd("<b>Edge Case Analysis Table</b>") + tb(["Scenario", "Happy Path Assumption", "Edge Case", "Design Response"], [["File upload", "User uploads a valid image", "User uploads 2GB video", "Show file size limit, provide compression option"], ["Form submission", "User fills all fields correctly", "User submits empty form", "Inline validation with specific error messages"], ["Search", "User types a common query", "User types SQL injection attempt", "Sanitize input, show no results, log attempt"], ["Multi-user editing", "One user edits at a time", "Two users edit the same field", "Real-time conflict resolution or last-write-wins with history"], ["Notification", "User sees notification immediately", "User has 10,000 unread notifications", "Batch notifications, aggregate by type, show most important"], ["Payment", "Payment succeeds on first try", "Payment fails after charge but before confirmation", "Idempotency key, show clear error, retry logic"]]) + bd("Mentioning 2-3 edge cases unprompted in a product design interview signals that you think about production systems and real users, not just ideal scenarios."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "edge-cases", "failure-modes", "staff-plus", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-7",
    "title": "Business Model Awareness: Revenue, Monetization & Unit Economics",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Staff+ engineers must understand how their product makes money. Business model awareness informs prioritization — if you know what drives revenue, you make better trade-off decisions. At FAANG, every engineer is expected to understand the business context of their work.") + bd("<b>FAANG Business Models</b>") + tb(["Company", "Primary Revenue Driver", "Key Metrics", "Product Implication"], [["Google", "Advertising (search, display, YouTube)", "CPC, CTR, Ad Impressions, Query Volume", "Speed and relevance directly impact revenue. Latency improvements = revenue gains."], ["Amazon", "E-commerce + AWS (cloud)", "GMV, Prime subscribers, AWS ACV", "Customer experience drives repeat purchases. Platform reliability drives AWS retention."], ["Meta", "Advertising (social, feed, stories)", "DAU/MAU, Ad Load, CPM, Time Spent", "Engagement metrics directly correlate with ad revenue. Feed quality is paramount."], ["Apple", "Hardware + Services (App Store, Apple Music)", "ASP, Installed Base, Services ARPU", "Ecosystem lock-in drives repeat hardware purchases. Privacy is a competitive moat."], ["Netflix", "Subscription (streaming)", "Subscriber Count, Churn Rate, ARPU", "Content investment is justified by subscriber acquisition and retention. Streaming quality reduces churn."], ["Microsoft", "Cloud (Azure, M365) + Enterprise", "Azure Revenue, M365 Seat Count, Commercial ARR", "Enterprise contracts drive predictable revenue. Integration across products creates switching costs."], ["Spotify", "Subscription (Premium) + Advertising (Free)", "MAU, Premium Subscribers, ARPU", "Conversion from free to premium is the key growth lever. Ad experience affects both revenue and churn."]]) + bd("<b>Unit Economics Deep Dive</b>") + mg(["<b>LTV (Customer Lifetime Value):</b> Total revenue a customer generates over their relationship with your product. LTV = ARPU x Average Lifetime.", "<b>CAC (Customer Acquisition Cost):</b> Total cost to acquire a customer, including marketing, sales, and onboarding. LTV:CAC ratio should be > 3:1 for a healthy business.", "<b>Payback Period:</b> How long it takes to recover CAC through gross margin. Under 12 months is ideal for SaaS.", "<b>Gross Margin:</b> Revenue minus cost of goods sold (COGS). High-margin products (software) subsidize low-margin products (hardware) in platform businesses.", "<b>Churn Rate:</b> Percentage of customers who stop using the product in a given period. Monthly churn of 5% means you lose ~46% of customers annually."]) + bd("When designing a feature, ask: \"How does this affect LTV, CAC, or churn?\" Connecting your product decision to unit economics is a Staff+-level differentiator."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "business-model", "monetization", "unit-economics", "staff-plus", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-8",
    "title": "Competitive Analysis: Positioning, Differentiation & Moats",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Staff+ engineers must understand the competitive landscape. Every product decision exists in a market context — competitors, substitutes, and evolving user expectations. Competitive analysis informs whether you should build, buy, partner, or invest differently.") + bd("<b>Competitive Analysis Frameworks</b>") + mg(["<b>Porter's Five Forces:</b> Industry rivalry, threat of new entrants, threat of substitutes, supplier power, buyer power. Use this to assess structural attractiveness.", "<b>SWOT Analysis:</b> Strengths, Weaknesses, Opportunities, Threats. Best for positioning your product relative to competitors.", "<b>Feature Comparison Matrix:</b> Compare your product against 2-3 competitors across key dimensions. Identify gaps you should fill and strengths you should defend.", "<b>Blue Ocean Strategy:</b> Create uncontested market space by offering something unique rather than competing on the same dimensions as everyone else.", "<b>Competitive Moats:</b> Network effects, brand, scale economies, switching costs, data advantages, IP protection, and regulatory barriers."]) + bd("<b>Product Positioning Table</b>") + tb(["Dimension", "Your Product", "Competitor A", "Competitor B", "Opportunity"], [["Target User", "Enterprise teams", "SMBs", "Individual professionals", "Mid-market gap"], ["Core Strength", "Security compliance", "Ease of use", "AI-powered features", "Combine compliance + AI"], ["Key Weakness", "Steep learning curve", "Limited integrations", "No offline mode", "Improve onboarding"], ["Pricing Model", "Per-seat annual", "Freemium", "Usage-based", "Tiered hybrid model"], ["Distribution", "Sales-led", "Product-led growth", "Self-serve", "Add self-serve free tier"], ["Switching Cost", "Data export friction", "Low — no lock-in", "Moderate — templates", "Increase via integrations and automation"]]) + bd("In interviews, show you understand the competitive landscape by mentioning 1-2 competitors and how your proposed feature creates differentiation. Avoid claiming your product has no competitors — this signals naivete."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "competitive-analysis", "positioning", "moats", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-9",
    "title": "Technical-Product Trade-Offs: Speed vs Quality vs Cost",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Staff+ engineers live at the intersection of technical feasibility and product desirability. The ability to articulate technical-product trade-offs clearly — and recommend a path — is a core evaluation criterion in Staff+ product sense interviews.") + bd("<b>The Trade-Off Triangle</b>") + mg(["<b>Speed:</b> Time to market. A faster delivery captures more user feedback and revenue sooner, but may incur technical debt or cut quality corners.", "<b>Quality:</b> Reliability, UX polish, scalability, maintainability. Higher quality costs more time and resources but reduces future friction and churn.", "<b>Cost:</b> Engineering resources, infrastructure, ongoing maintenance. Every decision has a cost that must be justified by expected value.", "<b>The Constraint:</b> You can optimize for at most two of three. Fast + High Quality = Expensive. Fast + Cheap = Low Quality. High Quality + Cheap = Slow."]) + bd("<b>Trade-Off Analysis Framework</b>") + tb(["Decision", "Speed Impact", "Quality Impact", "Cost Impact", "Recommendation"], [["Use existing component library vs build custom", "Faster: reuse existing", "Lower: limited to library capabilities", "Lower: no new development", "Use library for MVP, custom later if justified"], ["Ship with known but low-impact bug vs delay", "Faster: ship now", "Lower: users may encounter minor issue", "Neutral", "Ship with bug tracker, fix in next sprint"], ["Build vs buy third-party solution", "Faster: integrate existing", "Variable: vendor quality varies", "Higher: licensing costs", "Buy if core competency not affected, build otherwise"], ["Full test coverage vs critical path only", "Slower: more dev time", "Higher: fewer regressions", "Higher: more test infra", "Critical path coverage for MVP, full coverage later"], ["Single-tenant vs multi-tenant architecture", "Slower: more upfront design", "Higher: better isolation", "Higher: more infrastructure", "Multi-tenant for SaaS, single-tenant for enterprise deals"]]) + bd("<b>Framing Trade-Offs in Interviews</b>") + mg(["<b>Acknowledge the trade-off explicitly:</b> \"There is a tension between shipping quickly and building a robust system. Here is how I think about it.\"", "<b>Use data to inform the decision:</b> \"If we delay by 2 months, we lose the holiday season uplift. The cost of a quick MVP is 3 weeks of tech debt paydown afterward.\"", "<b>Recommend with rationale:</b> \"I recommend the faster path with a documented debt item to revisit in Q2.\"", "<b>Discuss risk mitigation:</b> \"To offset speed risk, we will add monitoring and a feature flag to roll back quickly if issues arise.\"", "<b>Show growth awareness:</b> \"This short-term trade-off is acceptable because the system is still finding product-market fit. As we scale, we will invest in quality.\""]) + bd("The best Staff+ candidates don't avoid trade-offs — they surface them clearly and make defensible recommendations."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "trade-offs", "speed-vs-quality", "technical-product", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-10",
    "title": "The Product Design Interview: End-to-End Framework",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("The product design interview is the centerpiece of FAANG product sense evaluation. You are given an open-ended prompt — \"Design a feature for X\" — and evaluated on your process, not your final design. The CIRCLES method is the most widely recommended structure.") + bd("<b>CIRCLES Method</b>") + mg(["<b>C — Comprehend:</b> Restate the problem in your own words. Confirm scope, constraints, and goals with the interviewer. Do not assume anything.", "<b>I — Identify:</b> Define the target user persona. Who exactly are you designing for? A new user? A power user? A specific demographic?", "<b>R — Report:</b> State the user's core need or job to be done. \"The user needs to accomplish X because Y.\"", "<b>C — Cause:</b> Identify the current pain point or gap. What prevents users from achieving their goal today? What is the baseline?", "<b>L — List:</b> Brainstorm 3-5 possible solutions. Do not converge too early. Be creative but grounded in feasibility.", "<b>E — Evaluate:</b> Compare your solutions against success criteria. Use a trade-off matrix: impact, effort, risk, strategic alignment.", "<b>S — Suggest:</b> Recommend one solution with clear rationale. Describe the user flow, key screens, edge cases, and success metrics."]) + bd("<b>Interview Structure Timeline</b>") + tb(["Phase", "Duration", "Key Activities", "Common Mistake"], [["Comprehend + Clarify", "2-3 min", "Restate prompt, ask clarifying questions, define scope", "Diving into solution without understanding the problem"], ["User + Need Definition", "2-3 min", "Define persona, identify job to be done", "Designing for \"everyone\" — too broad"], ["Ideation + Brainstorming", "3-4 min", "Generate 3-5 diverse solutions", "Falling in love with the first idea"], ["Evaluation + Trade-offs", "2-3 min", "Compare solutions, discuss pros/cons", "Ignoring trade-offs or being unrealistic"], ["Recommendation + Flow", "5-7 min", "Walk through the user flow, key screens, edge cases", "Too much detail on one screen, or too high-level"], ["Metrics + Success", "2-3 min", "Define success metrics, counter metrics, experiment design", "Not mentioning how to measure success"]]) + bd("The total interview is typically 30-45 minutes. Pacing matters — allocate your time deliberately and watch for the interviewer's cues."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "product-design", "circles", "interview-framework", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-11",
    "title": "Feature Sizing & Incremental Delivery",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Staff+ engineers know that big launches are risky. The best product thinkers break features into incremental releases that deliver value early, reduce risk, and allow course correction based on real feedback.") + bd("<b>Incremental Delivery Principles</b>") + mg(["<b>Thinnest Viable Slice:</b> What is the absolute minimum end-to-end version of this feature that delivers user value? Ship this first.", "<b>Value Each Release:</b> Every incremental release should provide standalone value, not just be a step toward the final vision.", "<b>Risk-First Delivery:</b> De-risk the most uncertain aspects of the feature first. If user adoption is the risk, test that before building the full system.", "<b>Feature Flags:</b> Ship code behind feature flags to enable gradual rollouts, A/B testing, and instant rollback without deployment.", "<b>Phased Rollout:</b> Start with 1% of users, then 5%, 10%, 25%, 50%, 100%. Monitor metrics and roll back if regressions appear."]) + bd("<b>Phased Rollout Plan Example</b>") + tb(["Phase", "Scope", "Users", "Success Criteria", "Duration"], [["Phase 1: MVP", "Core flow, critical path only, 1 platform", "Internal dogfooding (10 users)", "Functional completion, no critical bugs", "2-3 weeks"], ["Phase 2: Beta", "MVP + basic edge cases, 1 platform", "Opt-in beta (1% of users)", "Activation rate > 40%, error rate < 1%", "2 weeks"], ["Phase 3: Gradual Rollout", "Full flow, most edge cases, 2 platforms", "5% -> 25% -> 50% of users", "Metric lift statistically significant, no metric degradation", "3-4 weeks"], ["Phase 4: General Availability", "All edge cases, all platforms, internationalization", "100% of users", "Sustained metric improvement, positive user feedback", "1 week ramp"]]) + bd("<b>Interview Application</b>") + mg(["When proposing a feature, automatically include a phased rollout plan. This shows you think about delivery, not just design.", "Size your MVP honestly. Underestimating effort is a red flag. Say: \"The MVP would be approximately 3 engineer-weeks covering the core flow.\"", "Discuss what you would defer: \"In phase 1, we defer internationalization and advanced analytics. Those can be added in phase 3 based on adoption.\"", "Propose experiment gates between phases: \"Before moving from beta to 25%, we need to see a statistically significant improvement in the target metric with no degradation in the counter metric.\""]) + bd("Incremental delivery thinking separates product designers from product shippers. Staff+ engineers are expected to be the latter."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "feature-sizing", "mvp", "phased-rollout", "incremental-delivery", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-12",
    "title": "Stakeholder Management for Product Decisions",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("At Staff+, product decisions are rarely made in isolation. You navigate competing priorities from product managers, designers, data scientists, legal, compliance, and executive stakeholders. Your ability to build alignment around product decisions is as important as the quality of the decisions themselves.") + bd("<b>Stakeholder Types in Product Decisions</b>") + mg(["<b>The Visionary (PM):</b> Focused on roadmap, user impact, and strategic narrative. They care about what we build and why. Partner with them on problem definition and success criteria.", "<b>The Realist (Engineering):</b> Focused on feasibility, technical debt, and maintainability. They care about how we build. Involve them early in scoping and trade-off decisions.", "<b>The Advocate (Design):</b> Focused on user experience, consistency, and craft. They care about how it feels. Give them constraints early, not after they have designed something.", "<b>The Skeptic (Data Science):</b> Focused on evidence, statistical rigor, and measurable impact. They care about whether it works. Bring them metrics hypotheses and experiment designs.", "<b>The Guardian (Legal/Compliance):</b> Focused on risk, regulation, and policy. They care about what we must not do. Proactively flag decisions with compliance implications.", "<b>The Decider (Executive):</b> Focused on strategy, resourcing, and portfolio trade-offs. They care about what gets funded. Frame recommendations in terms of ROI, risk, and strategic alignment."]) + bd("<b>Building Alignment Framework</b>") + tb(["Step", "Action", "Key Question", "Output"], [["1. Map stakeholders", "Identify all parties with a stake in the decision", "Who cares about this and why?", "Stakeholder map with influence/interest"], ["2. Understand perspectives", "Meet individually to understand each stakeholder's position and motivation", "What does success look like for them?", "List of requirements and concerns per stakeholder"], ["3. Find common ground", "Identify shared goals and acceptable trade-offs", "Where does our Venn diagram overlap?", "Shared success criteria document"], ["4. Propose and iterate", "Share a proposal that balances key concerns", "Does this work for everyone?", "Revised proposal with stakeholder input"], ["5. Document and commit", "Write down the decision, rationale, and expected outcomes", "What did we agree on?", "Decision log with owners and timelines"]]) + bd("In interviews, when asked about a product decision, naturally include stakeholder considerations: \"I would socialize this with the PM and data science team to validate my assumptions before committing to a direction.\""),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "stakeholder-management", "alignment", "influence", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-13",
    "title": "Data-Informed Decision Making: A/B Testing & Experiment Design",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Staff+ engineers make data-informed — not data-driven — decisions. The distinction matters: data informs judgment, but judgment ultimately decides. Strong product answers include an experiment design that validates the proposed feature.") + bd("<b>A/B Testing Fundamentals</b>") + mg(["<b>Null Hypothesis (H0):</b> The feature has no effect on the target metric. You need sufficient evidence to reject this.", "<b>Alternative Hypothesis (H1):</b> The feature has a positive effect on the target metric. Set a minimum detectable effect (MDE) before starting.", "<b>Statistical Significance (p-value):</b> Generally p < 0.05 is considered significant. But at FAANG scale, even tiny effects can be significant — focus on practical significance.", "<b>Power (1 - beta):</b> The probability of detecting an effect if it truly exists. Aim for 80% power. Underpowered experiments waste resources and miss real effects.", "<b>Sample Size Calculation:</b> Depends on baseline conversion rate, MDE, significance level, and power. Use online calculators. Larger MDE = smaller sample needed.", "<b>Duration:</b> Run for at least 1 full business cycle (1-2 weeks) to capture day-of-week effects. Avoid holiday periods, launch events, or major news cycles."]) + bd("<b>Experiment Design Checklist</b>") + tb(["Element", "Question to Answer", "Common Pitfall"], [["Target Metric", "What metric will this feature directly impact?", "Choosing a metric that cannot move in the experiment window"], ["Counter Metric", "What might degrade while the target improves?", "Not tracking negative side effects"], ["Population", "Which users are included in the experiment?", "Including users who cannot experience the feature"], ["Sample Size", "How many users needed for statistical significance?", "Underpowered experiment leading to inconclusive results"], ["Duration", "How long will the experiment run?", "Ending early when results look positive (peeking)"], ["Segments", "What user segments might respond differently?", "Averaging across segments and missing heterogeneous effects"], ["Guardrails", "What metrics must not degrade?", "Shipping a feature that improves engagement but crashes the app"], ["Decision Criteria", "What threshold determines launch vs kill?", "Moving goalposts after seeing results"]]) + bd("<b>Interview Application</b>") + mg(["When proposing a feature, always describe the experiment: \"I would run a 2-week A/B test with 10% of users, measuring weekly active usage as the primary metric and crash rate as the counter metric.\"", "Discuss novelty effects: \"Users might engage more initially just because it is new. I would run the experiment for at least 2 weeks to let the novelty effect decay.\"", "Address network effects: \"If this feature has network effects, a standard A/B test may not work. I would consider a switchback experiment or a time-series analysis.\"", "Be honest about limitations: \"Not every feature can be A/B tested. For fundamental UX changes, consider pre/post analysis with matched cohorts.\""]) + bd("Experiment design shows the interviewer that you think rigorously about evidence and don't just chase intuition."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "ab-testing", "experiment-design", "data-informed", "metrics", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-14",
    "title": "Platform vs Product Thinking",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("At Staff+ level, you will work on platforms and internal products, not just user-facing features. Platform thinking requires a different product mindset: your users are engineers, your success is measured by adoption and developer experience, and your features are APIs and abstractions.") + bd("<b>Platform vs Product: Key Differences</b>") + tb(["Dimension", "Product Thinking", "Platform Thinking"], [["Primary User", "End customer", "Internal engineers or external developers"], ["Value Proposition", "Solves a user problem directly", "Enables others to solve user problems"], ["Success Metric", "User engagement, revenue, retention", "Adoption rate, API call volume, developer NPS"], ["Decision Making", "User research + data + intuition", "Customer requests + abstraction strategy + migration cost"], ["Speed vs Quality", "Ship fast, iterate based on feedback", "Get the API right — changing it breaks consumers"], ["Innovation Model", "Feature-driven, user-need driven", "Capability-driven, enable new use cases"], ["Failure Mode", "Building the wrong feature", "Building the wrong abstraction — costly to undo"], ["Investment Horizon", "Quarterly/annually", "Multi-year platform bet"]]) + bd("<b>Platform Thinking Principles</b>") + mg(["<b>API-First Design:</b> Design the interface before the implementation. A clean API surfaces the right abstractions and hides implementation complexity.", "<b>Internal Open Source:</b> Treat internal platforms like open source projects. Clear docs, RFC process, deprecation policy, and community management.", "<b>Dogfooding:</b> Use your own platform before asking others to. The pain of your own abstractions will make you a better platform builder.", "<b>Migration Path:</b> Every platform change should include a migration path. Breaking changes without a migration plan destroy trust and adoption.", "<b>SLAs for Internal Products:</b> Treat internal platform reliability with the same rigor as external products. Internal downtime still costs the company money.", "<b>Adoption Over Features:</b> A platform with fewer features and high adoption is better than a feature-rich platform no one uses. Focus on removing adoption barriers."]) + bd("In interviews, if asked to design a platform or internal tool, explicitly acknowledge the shift in thinking. Mention your users are engineers and your goal is to 10x their productivity, not to build a consumer-grade UX."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "platform-thinking", "api-first", "developer-experience", "internal-products", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-15",
    "title": "Product Sense for Infrastructure & Internal Tools",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Infrastructure and internal tools are the backbone of every FAANG company. Product sense for internal products requires a different skill set — you are solving for developer productivity, reliability, and operational efficiency rather than end-user delight.") + bd("<b>Unique Challenges of Internal Products</b>") + mg(["<b>Limited User Base:</b> You may have 50-500 internal users instead of millions. This limits A/B testing and makes qualitative feedback more important.", "<b>Captive Audience:</b> Internal users cannot choose a competitor. This creates a risk of ignoring user experience — good internal products actively earn adoption.", "<b>Higher Switching Cost:</b> Migrating internal tools requires coordinating many teams, updating docs, and managing transition periods. Changes are expensive.", "<b>Less UX Investment:</b> Internal tools often suffer from poor UX. Staff+ engineers recognize that even small UX improvements in internal tools compound across hundreds of engineers.", "<b>Direct Feedback Loop:</b> Your users sit a Slack message away. This can be a blessing (rapid feedback) or a curse (noise, entitlement). Set clear channels and expectations."]) + bd("<b>Measuring Internal Product Success</b>") + tb(["Metric", "What It Measures", "How to Improve"], [["Adoption Rate", "% of eligible teams using your tool", "Reduce onboarding friction, better docs, clear value prop"], ["Time to First Success", "How long until a new user gets value", "Improve onboarding flow, provide templates, better defaults"], ["Task Completion Rate", "% of users who successfully complete their task", "Fix UX issues, improve error messages, better defaults"], ["User Satisfaction (NPS)", "How likely users are to recommend your tool", "Fix top pain points, add requested features, reduce bugs"], ["Support Request Volume", "How many questions or issues arise", "Improve docs, fix common problems, better self-service"], ["Uptime / Reliability", "Is the tool available when needed?", "Invest in SLOs, monitoring, incident response"], ["Time Saved", "How much more productive users become", "Automate common tasks, improve performance, reduce steps"]]) + bd("<b>Staff+ Product Sense for Infrastructure</b>") + mg(["Start with the developer workflow. Map the end-to-end journey of an engineer making a change: from clone to deploy. Identify every friction point.", "Quantify the cost of friction. If your build system adds 5 minutes per build and 1000 engineers build 5 times/day, that is 41,667 hours/year of wasted compute time.", "Treat infrastructure as a product. Write a README. Add a getting-started guide. Create a support channel. Measure NPS. Ship a roadmap.", "Honor your API contracts. Internal consumers depend on your infrastructure. Breaking changes erode trust. Use semantic versioning, deprecation notices, and migration guides."]) + bd("Infrastructure product sense is increasingly evaluated at Staff+ because platform teams represent a growing percentage of engineering headcount at FAANG."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "infrastructure", "internal-tools", "developer-experience", "platform", "interview-prep"]
})

S.append({
    "id": "product-sense-staff-16",
    "title": "Common Product Sense Interview Questions & Rubrics",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("Understanding the types of questions asked and how they are scored helps you focus your preparation. FAANG product sense interviews follow predictable patterns.") + bd("<b>Common Question Types</b>") + mg(["<b>Design a Feature:</b> \"Design a [feature] for [product].\" Example: Design a video-sharing feature for Google Docs. Tests: user empathy, structured thinking, creativity, trade-off awareness.", "<b>Improve an Existing Feature:</b> \"How would you improve [existing feature]?\" Example: How would you improve the YouTube search experience? Tests: product usage, observation skills, metrics thinking.", "<b>Metrics Definition:</b> \"How would you measure success for [feature/product]?\" Example: How would you measure success for a new messaging product? Tests: metrics hierarchy, counter metrics, experiment design.", "<b>Prioritization:</b> \"We have these ideas — which should we build first?\" Example: Prioritize these 5 features for Instagram Reels. Tests: structured comparison, business awareness, judgment.", "<b>Strategy:</b> \"Should we enter this market?\" Example: Should Uber add a meal kit delivery service? Tests: first-principles thinking, competitive analysis, business model awareness.", "<b>Diagnose a Problem:</b> \"A metric dropped 15%. Why?\" Example: Facebook Marketplace listings dropped 20%. What happened? Tests: data analysis, root cause thinking, systematic investigation."]) + bd("<b>Scoring Rubric (FAANG Standard)</b>") + tb(["Dimension", "Weak (1-2)", "Good (3)", "Excellent (4-5)"], [["Problem Definition", "Jumps to solution without defining the problem", "Briefly clarifies the goal", "Spends 3-4 minutes on problem definition, user persona, and success criteria"], ["User Empathy", "Designs for self, assumes all users are the same", "Considers one user persona", "Identifies multiple personas, discusses edge cases, considers accessibility"], ["Structure", "Disorganized, bounces between ideas", "Uses a rough structure", "Clear framework (CIRCLES or similar), deliberate pacing, transitions between phases"], ["Creativity", "Obvious, copycat ideas", "One or two novel angles", "Multiple creative solutions, thoughtful evaluation of trade-offs"], ["Metrics & Data", "No mention of metrics", "Mentions one metric", "Define primary metric, counter metric, experiment design, statistical considerations"], ["Trade-off Awareness", "Assumes no trade-offs", "Mentions trade-offs vaguely", "Explicitly discusses speed/quality/cost trade-offs, makes a defensible recommendation"], ["Business Context", "Ignores business reality", "Briefly mentions revenue", "Connects to business model, competitive landscape, unit economics, strategic priorities"]]) + bd("<b>Preparation Strategy</b>") + mg(["Practice 15-20 product design questions aloud. Record yourself. Check your time allocation.", "Build a question bank from Glassdoor, LeetCode Discuss, and interview prep books.", "Have 3-4 frameworks ready: CIRCLES for feature design, AARA for metrics, RICE for prioritization.", "Know 2 products from each FAANG company deeply. Understand their metrics, business model, and recent changes.", "Practice with a timer. 45-minute interviews go fast. Aim for 3-4 min problem definition, 5-7 min solution, 2-3 min metrics."]) + bd("The most common feedback for candidates who fail product sense is: \"Good ideas, but lacked structure.\" Framework beats brilliance."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "interview-questions", "rubrics", "preparation", "staff-plus", "faang"]
})

S.append({
    "id": "product-sense-staff-17",
    "title": "References & Further Reading",
    "category": "product",
    "subcategory": "Staff+ Interviewing",
    "description": bd("This guide synthesizes frameworks and insights from the best product thinking resources available. Deepen your preparation with these curated references.") + bd("<b>Books</b>") + mg(["<b>Inspired — Marty Cagan:</b> The definitive book on modern product management. Covers product discovery, product strategy, and the role of engineers in product decisions.", "<b>Continuous Discovery Habits — Teresa Torres:</b> Practical framework for running continuous product discovery with opportunity solution trees.", "<b>The Mom Test — Rob Fitzpatrick:</b> How to talk to customers and learn if your idea is good without leading them or getting false positives.", "<b>Escaping the Build Trap — Melissa Perri:</b> How to shift from output-driven (shipping features) to outcome-driven (delivering value) product development.", "<b>Hooked — Nir Eyal:</b> The habit formation model for products. Useful for understanding engagement and retention mechanics.", "<b>Measure What Matters — John Doerr:</b> The OKR framework used across FAANG. Essential for understanding how product goals are set and measured.", "<b>Good Strategy Bad Strategy — Richard Rumelt:</b> Teaches you to distinguish between real strategy and aspirational fluff. Builds strategic thinking muscles."]) + bd("<b>Articles & Frameworks</b>") + mg(["<b>RICE Scoring — Intercom:</b> The original RICE prioritization framework article. Practical for interview preparation.", "<b>Jobs to Be Done — Clayton Christensen:</b> The theory behind JTBD. Understanding the theory helps you apply it better in interviews.", "<b>Google's HEART Framework:</b> Happiness, Engagement, Adoption, Retention, Task Success. Google's UX measurement framework. Useful for metrics questions.", "<b>AARA Framework — Exponent:</b> Align, Analyze, Recommend, Assess. A structured approach to metrics questions in product interviews.", "<b>CIRCLES Method — Lewis C. Lin:</b> The original CIRCLES framework from his book. The most widely recommended structure for product design interviews.", "<b>Goodhart's Law:</b> \"When a measure becomes a target, it ceases to be a good measure.\" Essential for metrics discussions.", "<b>Product Strategy Canvas:</b> A one-page template for defining product vision, target users, needs, value proposition, and success metrics."]) + bd("<b>Practice Platforms</b>") + mg(["<b>Pramp:</b> Free peer-to-peer mock interviews. Practice product design with other candidates and get structured feedback.", "<b>Exponent:</b> FAANG-focused interview prep platform with product sense courses and mock interview videos.", "<b>Glassdoor:</b> Read real interview questions from each company. Filter by role and seniority level.", "<b>LeetCode Discuss:</b> The product management section has real questions and detailed answer discussions.", "<b>Product School Slack Communities:</b> Join product management communities for feedback on your practice answers."]) + bd("<b>Final Advice</b>") + mg(["<b>Practice deliberately:</b> 20+ mock interviews with structured feedback will improve your score more than 100 hours of reading.", "<b>Record yourself:</b> You will spot rambling, filler words, and pacing issues you miss in the moment.", "<b>Think out loud:</b> Interviewers cannot read your mind. Narrate your thought process even when you are unsure.", "<b>Stay humble:</b> The best product sense answers include \"I don't know\" followed by \"but here is how I would find out.\"", "<b>Be opinionated:</b> FAANG wants leaders, not followers. Have a point of view. Defend it with evidence. Change it when evidence contradicts you."]) + bd("Good luck. Product sense is a skill — it can be learned, practiced, and mastered. The frameworks in this guide give you the foundation; your practice builds the fluency."),
    "language": "text",
    "sections": [],
    "tags": ["product-sense", "references", "books", "practice", "further-reading"]
})

